"use client";

import * as React from "react";
import {
  IconFolder,
  IconFolderFilled,
  IconFile,
  IconFileText,
  IconPhoto,
  IconFileTypePdf,
  IconFileSpreadsheet,
  IconFileCode,
  IconVideo,
  IconMusic,
  IconFileZip,
  IconChevronRight,
  IconLayoutGrid,
  IconList,
  IconFolderPlus,
  IconUpload,
  IconDownload,
  IconPencil,
  IconTrash,
  IconArrowRight,
  IconMenu2,
  IconX,
  IconCheck,
} from "@tabler/icons-react";

import {
  FileTree,
  type FileTreeNode,
  Breadcrumb,
  BreadcrumbList,
  BreadcrumbItem,
  BreadcrumbLink,
  BreadcrumbPage,
  BreadcrumbSeparator,
  BreadcrumbEllipsis,
  SearchInput,
  Button,
  Input,
  Badge,
  Img,
  Checkbox,
  ToggleGroup,
  ToggleGroupItem,
  Skeleton,
  EmptyState,
  ScrollArea,
  Separator,
  Tooltip,
  TooltipContent,
  TooltipTrigger,
  TooltipProvider,
  ResizablePanelGroup,
  ResizablePanel,
  ResizableHandle,
  ContextMenu,
  ContextMenuTrigger,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuSeparator,
  DropdownMenu,
  DropdownMenuTrigger,
  DropdownMenuContent,
  DropdownMenuRadioGroup,
  DropdownMenuRadioItem,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
  DialogClose,
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  Drawer,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
  DrawerDescription,
  cn,
} from "@gunjo/ui";

import {
  NODES,
  type FsNode,
  type FileType,
  getNode,
  childrenOf,
  isFolder,
  pathTo,
  formatSize,
  formatDate,
  TYPE_LABEL,
} from "./data";

/* ------------------------------------------------------------------ */
/* icons + view types                                                  */
/* ------------------------------------------------------------------ */

type ViewMode = "grid" | "list";
type SortField = "name" | "modified" | "size";
type SortDir = "asc" | "desc";

function TypeIcon({ type, className }: { type: FileType; className?: string }) {
  const map: Record<FileType, React.ComponentType<{ className?: string }>> = {
    folder: IconFolderFilled,
    image: IconPhoto,
    document: IconFileText,
    pdf: IconFileTypePdf,
    spreadsheet: IconFileSpreadsheet,
    code: IconFileCode,
    video: IconVideo,
    audio: IconMusic,
    archive: IconFileZip,
  };
  const I = map[type] ?? IconFile;
  return <I className={className} />;
}

const TYPE_BADGE: Partial<Record<FileType, React.ComponentProps<typeof Badge>["variant"]>> = {
  folder: "secondary",
  image: "info",
  pdf: "destructive",
  spreadsheet: "success",
  code: "warning",
};

/* ------------------------------------------------------------------ */
/* build the FileTree model (folders only) from the flat node list     */
/* ------------------------------------------------------------------ */

function buildTree(rootId: string): FileTreeNode[] {
  const kids = childrenOf(rootId).filter(isFolder);
  return kids.map((f) => {
    const sub = buildTree(f.id);
    const count = childrenOf(f.id).length;
    return {
      id: f.id,
      label: f.name,
      type: "folder" as const,
      children: sub.length ? sub : undefined,
      count: count ? `${count}` : undefined,
    };
  });
}

/* ------------------------------------------------------------------ */
/* page                                                                */
/* ------------------------------------------------------------------ */

export default function FilesPage() {
  const [currentId, setCurrentId] = React.useState<string>("home");
  const [view, setView] = React.useState<ViewMode>("grid");
  const [sortField, setSortField] = React.useState<SortField>("name");
  const [sortDir, setSortDir] = React.useState<SortDir>("asc");
  const [query, setQuery] = React.useState("");
  const [selected, setSelected] = React.useState<Set<string>>(new Set());
  const [lastClickedId, setLastClickedId] = React.useState<string | null>(null);
  const [loading, setLoading] = React.useState(true);

  // dialogs / sheets
  const [renameId, setRenameId] = React.useState<string | null>(null);
  const [renameValue, setRenameValue] = React.useState("");
  const [deleteId, setDeleteId] = React.useState<string | null>(null);
  const [mobileTreeOpen, setMobileTreeOpen] = React.useState(false);
  const [mobileDetailId, setMobileDetailId] = React.useState<string | null>(null);

  // local overlay state so rename/delete feel real without mutating the source
  const [renamed, setRenamed] = React.useState<Record<string, string>>({});
  const [deleted, setDeleted] = React.useState<Set<string>>(new Set());

  const treeNodes = React.useMemo(() => buildTree("home"), []);
  const expandedDefault = React.useMemo(() => ["home", "projects"], []);

  // fake loading skeleton when folder changes
  React.useEffect(() => {
    setLoading(true);
    const t = setTimeout(() => setLoading(false), 350);
    return () => clearTimeout(t);
  }, [currentId]);

  const displayName = React.useCallback(
    (n: FsNode) => renamed[n.id] ?? n.name,
    [renamed]
  );

  const crumbs = React.useMemo(() => pathTo(currentId), [currentId]);

  const items = React.useMemo(() => {
    let list = childrenOf(currentId).filter((n) => !deleted.has(n.id));
    if (query.trim()) {
      const q = query.toLowerCase();
      list = list.filter((n) => displayName(n).toLowerCase().includes(q));
    }
    const dir = sortDir === "asc" ? 1 : -1;
    list = [...list].sort((a, b) => {
      // folders always first
      if (isFolder(a) !== isFolder(b)) return isFolder(a) ? -1 : 1;
      let cmp = 0;
      if (sortField === "name") cmp = displayName(a).localeCompare(displayName(b));
      else if (sortField === "modified") cmp = a.modified.localeCompare(b.modified);
      else cmp = a.size - b.size;
      return cmp * dir;
    });
    return list;
  }, [currentId, query, sortField, sortDir, deleted, displayName]);

  const selectedNode =
    selected.size === 1 ? getNode([...selected][0]) : undefined;

  /* ---- navigation ---- */
  const navigateTo = React.useCallback((id: string) => {
    setCurrentId(id);
    setSelected(new Set());
    setLastClickedId(null);
    setQuery("");
  }, []);

  const openNode = React.useCallback(
    (n: FsNode) => {
      if (isFolder(n)) {
        navigateTo(n.id);
      } else {
        // open file -> show preview
        setSelected(new Set([n.id]));
        setMobileDetailId(n.id);
      }
    },
    [navigateTo]
  );

  /* ---- selection model (click / cmd-click / shift-range) ---- */
  const onItemClick = React.useCallback(
    (n: FsNode, e: React.MouseEvent | React.KeyboardEvent) => {
      const meta = "metaKey" in e && (e.metaKey || e.ctrlKey);
      const shift = "shiftKey" in e && e.shiftKey;
      setSelected((prev) => {
        const next = new Set(prev);
        if (shift && lastClickedId) {
          const ids = items.map((i) => i.id);
          const a = ids.indexOf(lastClickedId);
          const b = ids.indexOf(n.id);
          if (a !== -1 && b !== -1) {
            const [lo, hi] = a < b ? [a, b] : [b, a];
            for (let i = lo; i <= hi; i++) next.add(ids[i]);
            return next;
          }
        }
        if (meta) {
          if (next.has(n.id)) next.delete(n.id);
          else next.add(n.id);
          return next;
        }
        return new Set([n.id]);
      });
      setLastClickedId(n.id);
    },
    [items, lastClickedId]
  );

  const toggleCheckbox = React.useCallback((id: string) => {
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
    setLastClickedId(id);
  }, []);

  /* ---- actions ---- */
  const beginRename = (id: string) => {
    const n = getNode(id);
    if (!n) return;
    setRenameValue(displayName(n));
    setRenameId(id);
  };
  const commitRename = () => {
    if (renameId && renameValue.trim()) {
      setRenamed((r) => ({ ...r, [renameId]: renameValue.trim() }));
    }
    setRenameId(null);
  };
  const confirmDelete = () => {
    if (deleteId) {
      setDeleted((d) => new Set(d).add(deleteId));
      setSelected((s) => {
        const n = new Set(s);
        n.delete(deleteId);
        return n;
      });
    }
    setDeleteId(null);
  };

  const sortLabel: Record<SortField, string> = {
    name: "名前",
    modified: "更新日",
    size: "サイズ",
  };

  /* ---------------------------------------------------------------- */
  /* tree (shared between desktop rail and mobile drawer)              */
  /* ---------------------------------------------------------------- */
  const tree = (
    <nav aria-label="フォルダ" className="p-2">
      <FileTree
        nodes={treeNodes}
        selectionMode="single"
        selectedIds={[currentId]}
        defaultExpanded={expandedDefault}
        onNodeSelect={(node) => {
          navigateTo(node.id);
          setMobileTreeOpen(false);
        }}
      />
    </nav>
  );

  /* ---------------------------------------------------------------- */
  /* toolbar                                                          */
  /* ---------------------------------------------------------------- */
  const toolbar = (
    <div className="flex flex-col gap-3 border-b border-border p-3">
      {/* row 1: mobile menu + breadcrumb */}
      <div className="flex items-center gap-2 min-w-0">
        <Button
          variant="ghost"
          size="icon"
          className="md:hidden shrink-0"
          aria-label="フォルダツリーを開く"
          onClick={() => setMobileTreeOpen(true)}
        >
          <IconMenu2 className="h-5 w-5" />
        </Button>
        <PathBreadcrumb crumbs={crumbs} onNavigate={navigateTo} />
      </div>

      {/* row 2: search + actions */}
      <div className="flex flex-wrap items-center gap-2">
        <div className="min-w-0 flex-1 basis-48">
          <SearchInput
            value={query}
            onValueChange={setQuery}
            placeholder="このフォルダ内を検索…"
            aria-label="ファイルを検索"
          />
        </div>

        <Button variant="outline" size="sm" disabled>
          <IconFolderPlus className="h-4 w-4" />
          <span className="hidden sm:inline">新規フォルダ</span>
        </Button>
        <Button variant="outline" size="sm" disabled>
          <IconUpload className="h-4 w-4" />
          <span className="hidden sm:inline">アップロード</span>
        </Button>

        {/* sort: field via dropdown, direction toggles */}
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="ghost" size="sm">
              並び替え: {sortLabel[sortField]} {sortDir === "asc" ? "↑" : "↓"}
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end">
            <DropdownMenuLabel>並び替え</DropdownMenuLabel>
            <DropdownMenuRadioGroup
              value={sortField}
              onValueChange={(v) => setSortField(v as SortField)}
            >
              <DropdownMenuRadioItem value="name">名前</DropdownMenuRadioItem>
              <DropdownMenuRadioItem value="modified">更新日</DropdownMenuRadioItem>
              <DropdownMenuRadioItem value="size">サイズ</DropdownMenuRadioItem>
            </DropdownMenuRadioGroup>
            <DropdownMenuSeparator />
            <DropdownMenuRadioGroup
              value={sortDir}
              onValueChange={(v) => setSortDir(v as SortDir)}
            >
              <DropdownMenuRadioItem value="asc">昇順</DropdownMenuRadioItem>
              <DropdownMenuRadioItem value="desc">降順</DropdownMenuRadioItem>
            </DropdownMenuRadioGroup>
          </DropdownMenuContent>
        </DropdownMenu>

        {/* view toggle */}
        <ToggleGroup
          type="single"
          value={view}
          onValueChange={(v) => v && setView(v as ViewMode)}
          variant="outline"
          aria-label="表示モード"
        >
          <ToggleGroupItem value="grid" aria-label="グリッド表示" size="sm" className="px-2">
            <IconLayoutGrid className="h-4 w-4" />
          </ToggleGroupItem>
          <ToggleGroupItem value="list" aria-label="リスト表示" size="sm" className="px-2">
            <IconList className="h-4 w-4" />
          </ToggleGroupItem>
        </ToggleGroup>
      </div>
    </div>
  );

  /* ---------------------------------------------------------------- */
  /* file area                                                        */
  /* ---------------------------------------------------------------- */
  const selectionCount = selected.size;

  const fileArea = (
    <div className="flex h-full min-h-0 flex-col">
      {/* selection status line */}
      <div className="flex items-center justify-between px-3 py-2 text-xs text-muted-foreground" aria-live="polite">
        <span>
          {items.length}件
          {selectionCount > 0 ? ` · ${selectionCount}件を選択中` : ""}
        </span>
        {selectionCount > 0 && (
          <Button variant="link" size="sm" className="h-auto p-0 text-xs" onClick={() => setSelected(new Set())}>
            選択を解除
          </Button>
        )}
      </div>
      <Separator />
      <ScrollArea className="flex-1 min-h-0">
        <div className="p-3">
          {loading ? (
            <FileAreaSkeleton view={view} />
          ) : items.length === 0 ? (
            <EmptyState
              headingLevel={2}
              icon={<IconFolder className="h-8 w-8" />}
              title={query ? "一致する項目がありません" : "このフォルダは空です"}
              description={
                query
                  ? `「${query}」に一致する項目はありません。`
                  : "ファイルをアップロードするか、フォルダを作成して始めましょう。"
              }
              action={
                !query ? (
                  <Button size="sm" disabled>
                    <IconUpload className="h-4 w-4" />
                    ファイルをアップロード
                  </Button>
                ) : undefined
              }
              className="mt-6"
            />
          ) : view === "grid" ? (
            <ul
              role="listbox"
              aria-label={`${displayName(getNode(currentId)!)} 内のファイル`}
              aria-multiselectable="true"
              className="grid grid-cols-[repeat(auto-fill,minmax(150px,1fr))] gap-3"
            >
              {items.map((n) => (
                <FileGridItem
                  key={n.id}
                  node={n}
                  name={displayName(n)}
                  selected={selected.has(n.id)}
                  renaming={renameId === n.id}
                  renameValue={renameValue}
                  onRenameValue={setRenameValue}
                  onRenameCommit={commitRename}
                  onRenameCancel={() => setRenameId(null)}
                  onClick={(e) => onItemClick(n, e)}
                  onOpen={() => openNode(n)}
                  onCheckbox={() => toggleCheckbox(n.id)}
                  onRename={() => beginRename(n.id)}
                  onDelete={() => setDeleteId(n.id)}
                  onShowDetail={() => {
                    setSelected(new Set([n.id]));
                    setMobileDetailId(n.id);
                  }}
                />
              ))}
            </ul>
          ) : (
            <div role="listbox" aria-label={`${displayName(getNode(currentId)!)} 内のファイル`} aria-multiselectable="true">
              {/* list header */}
              <div className="hidden grid-cols-[2.5rem_1fr_7rem_8rem_6rem] items-center gap-2 px-2 py-1.5 text-xs font-medium text-muted-foreground sm:grid">
                <span aria-hidden />
                <span>名前</span>
                <span>種類</span>
                <span>更新日</span>
                <span className="text-right">サイズ</span>
              </div>
              <ul className="flex flex-col">
                {items.map((n) => (
                  <FileListItem
                    key={n.id}
                    node={n}
                    name={displayName(n)}
                    selected={selected.has(n.id)}
                    renaming={renameId === n.id}
                    renameValue={renameValue}
                    onRenameValue={setRenameValue}
                    onRenameCommit={commitRename}
                    onRenameCancel={() => setRenameId(null)}
                    onClick={(e) => onItemClick(n, e)}
                    onOpen={() => openNode(n)}
                    onCheckbox={() => toggleCheckbox(n.id)}
                    onRename={() => beginRename(n.id)}
                    onDelete={() => setDeleteId(n.id)}
                    onShowDetail={() => {
                      setSelected(new Set([n.id]));
                      setMobileDetailId(n.id);
                    }}
                  />
                ))}
              </ul>
            </div>
          )}
        </div>
      </ScrollArea>
    </div>
  );

  /* ---------------------------------------------------------------- */
  /* details pane                                                     */
  /* ---------------------------------------------------------------- */
  const details = <DetailsPane node={selectedNode} name={selectedNode ? displayName(selectedNode) : ""} crumbsFor={(id) => pathTo(id)} />;

  /* ---------------------------------------------------------------- */
  /* render                                                           */
  /* ---------------------------------------------------------------- */
  return (
    <TooltipProvider>
      <div className="flex h-screen flex-col bg-background text-foreground">
        <header className="flex items-center gap-2 border-b border-border px-4 py-3">
          <IconFolderFilled className="h-5 w-5 text-primary" aria-hidden />
          <h1 className="text-lg font-semibold">ファイル</h1>
        </header>

        <div className="flex min-h-0 flex-1">
          {/* desktop tree rail */}
          <aside className="hidden w-60 shrink-0 border-r border-border md:block">
            <ScrollArea className="h-full">{tree}</ScrollArea>
          </aside>

          {/* main + details (resizable on desktop) */}
          <div className="min-w-0 flex-1">
            {/* desktop: resizable main/detail */}
            <div className="hidden h-full lg:block">
              <ResizablePanelGroup direction="horizontal">
                <ResizablePanel defaultSize={70} minSize={45}>
                  <div className="flex h-full min-h-0 flex-col">
                    {toolbar}
                    <div className="min-h-0 flex-1">{fileArea}</div>
                  </div>
                </ResizablePanel>
                <ResizableHandle withHandle />
                <ResizablePanel defaultSize={30} minSize={18} maxSize={45}>
                  <ScrollArea className="h-full">{details}</ScrollArea>
                </ResizablePanel>
              </ResizablePanelGroup>
            </div>

            {/* tablet/mobile: stacked, details via sheet */}
            <div className="flex h-full min-h-0 flex-col lg:hidden">
              {toolbar}
              <div className="min-h-0 flex-1">{fileArea}</div>
            </div>
          </div>
        </div>

        {/* mobile tree drawer */}
        <Drawer open={mobileTreeOpen} onOpenChange={setMobileTreeOpen} direction="left">
          <DrawerContent side="left" className="w-72">
            <DrawerHeader className="flex items-center justify-between">
              <DrawerTitle>フォルダ</DrawerTitle>
              <Button variant="ghost" size="icon" aria-label="閉じる" onClick={() => setMobileTreeOpen(false)}>
                <IconX className="h-5 w-5" />
              </Button>
            </DrawerHeader>
            <DrawerDescription className="sr-only">移動先のフォルダを選択します。</DrawerDescription>
            <ScrollArea className="flex-1 min-h-0">{tree}</ScrollArea>
          </DrawerContent>
        </Drawer>

        {/* mobile / tablet detail sheet */}
        <Sheet
          open={mobileDetailId !== null && selectedNode !== undefined}
          onOpenChange={(o) => {
            if (!o) setMobileDetailId(null);
          }}
        >
          <SheetContent side="right" className="w-[88vw] max-w-sm overflow-y-auto p-0 lg:hidden">
            <div className="sr-only">
              <SheetTitle>詳細</SheetTitle>
              <SheetDescription>ファイルのプロパティとプレビュー</SheetDescription>
            </div>
            <DetailsPane node={selectedNode} name={selectedNode ? displayName(selectedNode) : ""} crumbsFor={(id) => pathTo(id)} embedded />
          </SheetContent>
        </Sheet>

        {/* rename dialog fallback is inline; delete confirm dialog: */}
        <Dialog open={deleteId !== null} onOpenChange={(o) => !o && setDeleteId(null)}>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>「{deleteId ? (renamed[deleteId] ?? getNode(deleteId)?.name) : ""}」を削除しますか？</DialogTitle>
              <DialogDescription>
                この項目はフォルダから移動されます。このデモでの削除はローカルでのみ反映されます。
              </DialogDescription>
            </DialogHeader>
            <DialogFooter>
              <DialogClose asChild>
                <Button variant="outline">キャンセル</Button>
              </DialogClose>
              <Button variant="destructive" onClick={confirmDelete}>
                <IconTrash className="h-4 w-4" />
                削除
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    </TooltipProvider>
  );
}

/* ================================================================== */
/* Breadcrumb with manual collapse for long paths                     */
/* ================================================================== */
function PathBreadcrumb({
  crumbs,
  onNavigate,
}: {
  crumbs: FsNode[];
  onNavigate: (id: string) => void;
}) {
  // collapse middle when > 4 deep
  const collapse = crumbs.length > 4;
  const head = crumbs[0];
  const tail = crumbs.slice(-2);
  const hidden = collapse ? crumbs.slice(1, -2) : [];

  const renderCrumb = (n: FsNode, isLast: boolean) =>
    isLast ? (
      <BreadcrumbPage className="truncate max-w-[40vw]">{n.name}</BreadcrumbPage>
    ) : (
      <BreadcrumbLink
        asChild
        className="cursor-pointer no-underline hover:underline truncate max-w-[30vw]"
      >
        <button type="button" onClick={() => onNavigate(n.id)}>
          {n.name}
        </button>
      </BreadcrumbLink>
    );

  return (
    <Breadcrumb className="min-w-0 overflow-hidden">
      <BreadcrumbList className="flex-nowrap">
        {!collapse ? (
          crumbs.map((n, i) => (
            <React.Fragment key={n.id}>
              <BreadcrumbItem>{renderCrumb(n, i === crumbs.length - 1)}</BreadcrumbItem>
              {i < crumbs.length - 1 && <BreadcrumbSeparator />}
            </React.Fragment>
          ))
        ) : (
          <>
            <BreadcrumbItem>{renderCrumb(head, false)}</BreadcrumbItem>
            <BreadcrumbSeparator />
            <BreadcrumbItem>
              <DropdownMenu>
                <DropdownMenuTrigger
                  className="flex h-9 items-center rounded px-1 hover:text-foreground focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring"
                  aria-label="省略されたフォルダを表示"
                >
                  <BreadcrumbEllipsis />
                </DropdownMenuTrigger>
                <DropdownMenuContent align="start">
                  {hidden.map((n) => (
                    <DropdownMenuRadioGroup key={n.id} value="">
                      <DropdownMenuRadioItem value={n.id} onClick={() => onNavigate(n.id)}>
                        {n.name}
                      </DropdownMenuRadioItem>
                    </DropdownMenuRadioGroup>
                  ))}
                </DropdownMenuContent>
              </DropdownMenu>
            </BreadcrumbItem>
            <BreadcrumbSeparator />
            {tail.map((n, i) => (
              <React.Fragment key={n.id}>
                <BreadcrumbItem>{renderCrumb(n, i === tail.length - 1)}</BreadcrumbItem>
                {i < tail.length - 1 && <BreadcrumbSeparator />}
              </React.Fragment>
            ))}
          </>
        )}
      </BreadcrumbList>
    </Breadcrumb>
  );
}

/* ================================================================== */
/* shared item context-menu wrapper                                   */
/* ================================================================== */
interface ItemActions {
  onOpen: () => void;
  onRename: () => void;
  onDelete: () => void;
  onShowDetail: () => void;
}

function ItemContextMenu({
  children,
  actions,
  isFolderItem,
}: {
  children: React.ReactNode;
  actions: ItemActions;
  isFolderItem: boolean;
}) {
  return (
    <ContextMenu>
      <ContextMenuTrigger asChild>{children}</ContextMenuTrigger>
      <ContextMenuContent>
        <ContextMenuItem onSelect={actions.onOpen}>
          {isFolderItem ? "フォルダを開く" : "開く / プレビュー"}
        </ContextMenuItem>
        <ContextMenuItem onSelect={actions.onRename}>
          <IconPencil className="h-4 w-4" /> 名前を変更
        </ContextMenuItem>
        <ContextMenuItem onSelect={() => alert("ダウンロード（デモ）")} disabled={isFolderItem}>
          <IconDownload className="h-4 w-4" /> ダウンロード
        </ContextMenuItem>
        <ContextMenuItem onSelect={() => alert("移動…（デモ）")}>
          <IconArrowRight className="h-4 w-4" /> 移動…
        </ContextMenuItem>
        <ContextMenuSeparator />
        <ContextMenuItem
          className="text-destructive-strong focus:bg-destructive-subtle focus:text-destructive-strong-foreground"
          onSelect={actions.onDelete}
        >
