const byId = new Map(NODES.map((n) => [n.id, n]));

export function getNode(id: string): FsNode | undefined {
  return byId.get(id);
}

export function childrenOf(id: string): FsNode[] {
  return NODES.filter((n) => n.parentId === id);
}

export function isFolder(n: FsNode): boolean {
  return n.kind === "folder";
}

/** breadcrumb chain from root to (and including) the given folder id */
export function pathTo(id: string): FsNode[] {
  const chain: FsNode[] = [];
  let cur: FsNode | undefined = byId.get(id);
  while (cur) {
    chain.unshift(cur);
    cur = cur.parentId ? byId.get(cur.parentId) : undefined;
  }
  return chain;
}

export function formatSize(bytes: number): string {
  if (bytes === 0) return "—";
  const units = ["B", "KB", "MB", "GB"];
  let val = bytes;
  let i = 0;
  while (val >= 1024 && i < units.length - 1) {
    val /= 1024;
    i++;
  }
  return `${val % 1 === 0 ? val : val.toFixed(1)} ${units[i]}`;
}

export function formatDate(iso: string): string {
  const d = new Date(iso);
  return d.toLocaleDateString("ja-JP", { year: "numeric", month: "long", day: "numeric" });
}

